import{_ as e,o as r,c as o,ag as a}from"./chunks/framework.OsDJF_Ea.js";const n="/docs/modules/arpeggiator.png",u=JSON.parse('{"title":"Arpeggiator","description":"","frontmatter":{},"headers":[],"relativePath":"modules/arpeggiator.md","filePath":"modules/arpeggiator.md"}'),s={name:"modules/arpeggiator.md"};function d(l,t,i,g,p,c){return r(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="arpeggiator" tabindex="-1">Arpeggiator <a class="header-anchor" href="#arpeggiator" aria-label="Permalink to &quot;Arpeggiator&quot;">​</a></h1><p><strong>Category:</strong> MIDI Effects</p><p>Takes incoming MIDI chords and plays them as arpeggiated sequences. Multiple patterns, clock sync, and hold/latch mode.</p><img src="'+n+'" alt="arpeggiator module"><h2 id="inputs" tabindex="-1">Inputs <a class="header-anchor" href="#inputs" aria-label="Permalink to &quot;Inputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>note</strong></td><td>MIDI note input. Connect from MIDIIn.</td></tr><tr><td><strong>gate</strong></td><td>Note gate. Arpeggiator collects notes while gates are high.</td></tr><tr><td><strong>velocity</strong></td><td>Note velocity for dynamics.</td></tr><tr><td><strong>rate</strong></td><td>Arpeggio speed. In free mode, controls Hz directly.</td></tr><tr><td><strong>pattern</strong></td><td>Select pattern via CV: up, down, up-down, down-up, random, as-played.</td></tr><tr><td><strong>length</strong></td><td>Gate length per step (0.1 = staccato, 1.0 = legato).</td></tr><tr><td><strong>hold</strong></td><td>Hold/latch toggle. When high, notes stay after key release.</td></tr><tr><td><strong>clock</strong></td><td>External clock for sync. Connect from Clock module.</td></tr><tr><td><strong>reset</strong></td><td>Reset arpeggio to step 1.</td></tr></tbody></table><h2 id="outputs" tabindex="-1">Outputs <a class="header-anchor" href="#outputs" aria-label="Permalink to &quot;Outputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>note_out</strong></td><td>Arpeggiated note. Connect to Oscillator or MIDIOut.</td></tr><tr><td><strong>gate_out</strong></td><td>Gate per step. Connect to ADSR.</td></tr><tr><td><strong>velocity_out</strong></td><td>Velocity per step.</td></tr></tbody></table><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><p>Place between MIDIIn and an Oscillator to turn chords into arpeggios. Connect a Clock to the clock input for tempo-locked patterns. Enable hold to sustain patterns after releasing keys.</p><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2>',11)])])}const m=e(s,[["render",d]]);export{u as __pageData,m as default};
